@using System.Threading
@inject IProductService ProductService
@implements IDisposable

<div class="product-search">
    <input type="text"
           placeholder="Search products…"
           @bind="searchText"
           @bind:event="oninput"
           @bind:after="OnSearchTextChanged" />

    @if (isLoading)
    {
        <div class="product-search-status">Searching…</div>
    }
    else if (errorMessage is not null)
    {
        <div class="product-search-error">
            <span>@errorMessage</span>
            <button @onclick="RetrySearch">Retry</button>
        </div>
    }
    else if (products is not null)
    {
        if (products.Count == 0)
        {
            <div class="product-search-status">No products found.</div>
        }
        else
        {
            <div class="product-search-results">
                @foreach (var product in products)
                {
                    <div class="product-card" @onclick="() => OnProductSelected.InvokeAsync(product)">
                        <img src="@product.ImageUrl" alt="@product.Name" loading="lazy" />
                        <h3>@product.Name</h3>
                        <p class="product-price">@product.Price.ToString("C")</p>
                    </div>
                }
            </div>
        }
    }
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private string searchText = string.Empty;
    private List<Product>? products;
    private bool isLoading;
    private string? errorMessage;

    private CancellationTokenSource? pendingCts;
    private Timer? debounceTimer;

    private async Task OnSearchTextChanged()
    {
        // Cancel any in-flight search immediately so the old request is abandoned.
        CancelPending();

        var query = searchText.Trim();
        if (string.IsNullOrEmpty(query))
        {
            products = null;
            errorMessage = null;
            isLoading = false;
            return;
        }

        // Restart the 300ms debounce timer.
        var tcs = new TaskCompletionSource();
        debounceTimer = new Timer(_ => tcs.TrySetResult(), null, 300, Timeout.Infinite);
        await tcs.Task;

        await ExecuteSearch(query);
    }

    private async Task RetrySearch()
    {
        var query = searchText.Trim();
        if (!string.IsNullOrEmpty(query))
        {
            await ExecuteSearch(query);
        }
    }

    private async Task ExecuteSearch(string query)
    {
        CancelPending();

        var cts = new CancellationTokenSource();
        pendingCts = cts;

        isLoading = true;
        errorMessage = null;
        products = null;

        try
        {
            var results = await ProductService.SearchAsync(query, cts.Token);

            // If this CTS was replaced, another search superseded us — discard results.
            if (cts.Token.IsCancellationRequested)
                return;

            products = results;
        }
        catch (OperationCanceledException)
        {
            // Search was intentionally cancelled; nothing to show.
            return;
        }
        catch (Exception)
        {
            if (cts.Token.IsCancellationRequested)
                return;

            errorMessage = "Something went wrong. Please try again.";
        }
        finally
        {
            // Only clear the loading flag if this is still the active search.
            if (pendingCts == cts)
            {
                isLoading = false;
            }
        }
    }

    private void CancelPending()
    {
        debounceTimer?.Dispose();
        debounceTimer = null;
        pendingCts?.Cancel();
        pendingCts?.Dispose();
        pendingCts = null;
    }

    public void Dispose()
    {
        CancelPending();
    }
}

